import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);

  const [tab, setTab] = useState('users');

  // ✅ NEW STATES
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;

  // ================= FETCH DATA =================
  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data || []));
    API.get('/admin/posts').then(res => setPosts(res.data || []));
    API.get('/admin/comments').then(res => setComments(res.data || []));
    API.get('/admin/messages').then(res => setMessages(res.data || []));
  }, []);

  // Reset page when tab/search/filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [tab, search, filter]);

  // ================= USER ACTIONS =================
  const toggleStatus = async (id) => {
    try {
      const { data } = await API.put(`/admin/users/${id}/status`);
      setUsers(users.map(u => (u._id === id ? data.user : u)));
    } catch {
      alert("Error updating user status.");
    }
  };

  // ================= POST ACTIONS =================
  const removePost = async (id) => {
    if (!window.confirm("Delete post?")) return;
    await API.delete(`/posts/${id}`);
    setPosts(posts.filter(p => p._id !== id));
  };

  const viewPost = (id) => navigate(`/posts/${id}`);

  // ================= COMMENT ACTIONS =================
  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  // ================= MESSAGE ACTIONS =================
  const markAsRead = async (id) => {
    const { data } = await API.put(`/admin/messages/${id}/read`);
    setMessages(messages.map(m => m._id === id ? (data.message || data) : m));
  };

  const deleteMessage = async (id) => {
    await API.delete(`/admin/messages/${id}`);
    setMessages(messages.filter(m => m._id !== id));
  };

  // ================= FILTER + SEARCH =================
  const getFilteredData = () => {
    let data = [];

    if (tab === 'users') data = users;
    if (tab === 'posts') data = posts;
    if (tab === 'comments') data = comments;
    if (tab === 'messages') data = messages;

    // 🔍 SEARCH
    data = data.filter(item => {
      const text = JSON.stringify(item).toLowerCase();
      return text.includes(search.toLowerCase());
    });

    // 🎯 FILTER
    if (filter !== 'all') {
      data = data.filter(item =>
        String(item.status || '').toLowerCase() === filter
      );
    }

    return data;
  };

  const filteredData = getFilteredData();

  // ================= PAGINATION =================
  const totalPages = Math.ceil(filteredData.length / itemsPerPage);

  const paginatedData = filteredData.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  // ================= STYLES =================
  const styles = {
    page: { padding: 20, textAlign: 'center' },
    tabs: { display: 'flex', gap: 10, justifyContent: 'center', marginBottom: 20 },
    btn: { padding: 8, cursor: 'pointer' },
    table: { width: '100%', borderCollapse: 'collapse' },
    th: { background: '#333', color: '#fff', padding: 10 },
    td: { padding: 10, borderBottom: '1px solid #ccc' },
    controls: { marginBottom: 20, display: 'flex', gap: 10, justifyContent: 'center' }
  };

  return (
    <div style={styles.page}>
      <h2>Admin Panel</h2>

      {/* ================= TABS ================= */}
      <div style={styles.tabs}>
        {['users', 'posts', 'comments', 'messages'].map(t => (
          <button key={t} onClick={() => setTab(t)} style={styles.btn}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      {/* ================= SEARCH + FILTER ================= */}
      <div style={styles.controls}>
        <input
          placeholder="Search..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />

        <select value={filter} onChange={e => setFilter(e.target.value)}>
          <option value="all">All</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
          <option value="new">New</option>
          <option value="read">Read</option>
        </select>
      </div>

      {/* ================= TABLE ================= */}
      <table style={styles.table}>
        <thead>
          <tr>
            {tab === 'users' && <>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Email</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </>}
            {tab === 'posts' && <>
              <th style={styles.th}>Title</th>
              <th style={styles.th}>Action</th>
            </>}
            {tab === 'comments' && <>
              <th style={styles.th}>Comment</th>
              <th style={styles.th}>Action</th>
            </>}
            {tab === 'messages' && <>
              <th style={styles.th}>Message</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </>}
          </tr>
        </thead>

        <tbody>
          {paginatedData.map(item => (
            <tr key={item._id}>
              
              {/* USERS */}
              {tab === 'users' && <>
                <td style={styles.td}>{item.name}</td>
                <td style={styles.td}>{item.email}</td>
                <td style={styles.td}>{String(item.status || '').toUpperCase()}</td>
                <td style={styles.td}>
                  <button onClick={() => toggleStatus(item._id)}>
                    Toggle
                  </button>
                </td>
              </>}

              {/* POSTS */}
              {tab === 'posts' && <>
                <td style={styles.td}>{item.title}</td>
                <td style={styles.td}>
                  <button onClick={() => viewPost(item._id)}>View</button>
                  <button onClick={() => removePost(item._id)}>Delete</button>
                </td>
              </>}

              {/* COMMENTS */}
              {tab === 'comments' && <>
                <td style={styles.td}>{item.body}</td>
                <td style={styles.td}>
                  <button onClick={() => deleteComment(item._id)}>Delete</button>
                </td>
              </>}

              {/* MESSAGES */}
              {tab === 'messages' && <>
                <td style={styles.td}>
                  {item.body || item.message || item.content}
                </td>
                <td style={styles.td}>
                  {String(item.status || '').toUpperCase()}
                </td>
                <td style={styles.td}>
                  {(['new', 'unread', ''].includes((item.status || '').toLowerCase())) && (
                    <button onClick={() => markAsRead(item._id)}>Read</button>
                  )}
                  <button onClick={() => deleteMessage(item._id)}>Delete</button>
                </td>
              </>}
            </tr>
          ))}
        </tbody>
      </table>

      {/* ================= PAGINATION ================= */}
      <div style={{ marginTop: 20 }}>
        <button disabled={currentPage === 1}
          onClick={() => setCurrentPage(p => p - 1)}>
          Prev
        </button>

        <span style={{ margin: '0 10px' }}>
          Page {currentPage} / {totalPages || 1}
        </span>

        <button disabled={currentPage === totalPages}
          onClick={() => setCurrentPage(p => p + 1)}>
          Next
        </button>
      </div>
    </div>
  );
};

export default AdminPage;
